CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE "ActionCatalogs" (
    "ActionId" character varying(50) NOT NULL,
    "TargetCompetency" character varying(50) NOT NULL,
    "ActionCategory" character varying(50) NOT NULL,
    "ActionType" character varying(50) NOT NULL,
    "Difficulty" character varying(20) NOT NULL,
    "EstimatedEffortHours" integer NOT NULL,
    "MinScore" numeric(3,2) NOT NULL,
    "MaxScore" numeric(3,2) NOT NULL,
    "ContentData" jsonb NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_ActionCatalogs" PRIMARY KEY ("ActionId"),
    CONSTRAINT "CK_ActionCatalogs_EffortHours" CHECK ("EstimatedEffortHours" >= 0),
    CONSTRAINT "CK_ActionCatalogs_ScoreRange" CHECK ("MinScore" <= "MaxScore")
);

CREATE TABLE "AssessmentCycles" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(150) NOT NULL,
    "StartDate" date NOT NULL,
    "EndDate" date NOT NULL,
    "Status" character varying(50) NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_AssessmentCycles" PRIMARY KEY ("Id")
);

CREATE TABLE "Competencies" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Code" character varying(100) NOT NULL,
    "Name" character varying(150) NOT NULL,
    "Category" character varying(50) NOT NULL,
    "Description" text,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Competencies" PRIMARY KEY ("Id")
);

CREATE TABLE "Departments" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(100) NOT NULL,
    "Code" character varying(50) NOT NULL,
    "Description" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Departments" PRIMARY KEY ("Id")
);

CREATE TABLE "ModelVersions" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "ModelName" character varying(100) NOT NULL,
    "Version" character varying(100) NOT NULL,
    "Description" text,
    "MicroF1" double precision,
    "MacroF1" double precision,
    "RocAuc" double precision,
    "HammingLoss" double precision,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_ModelVersions" PRIMARY KEY ("Id")
);

CREATE TABLE "Roles" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(50) NOT NULL,
    "Description" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Roles" PRIMARY KEY ("Id")
);

CREATE TABLE "JobRoles" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(100) NOT NULL,
    "DepartmentId" integer,
    "Description" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_JobRoles" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_JobRoles_Departments_DepartmentId" FOREIGN KEY ("DepartmentId") REFERENCES "Departments" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Employees" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeCode" character varying(50) NOT NULL,
    "FullName" character varying(150) NOT NULL,
    "Email" character varying(150) NOT NULL,
    "Age" integer NOT NULL,
    "Gender" character varying(30) NOT NULL,
    "DepartmentId" integer NOT NULL,
    "JobRoleId" integer NOT NULL,
    "ManagerId" integer,
    "Education" character varying(50) NOT NULL,
    "EducationField" character varying(100) NOT NULL,
    "BusinessTravel" character varying(100) NOT NULL,
    "MaritalStatus" character varying(50) NOT NULL,
    "DistanceFromHome" integer NOT NULL,
    "EnvironmentSatisfaction" integer NOT NULL,
    "JobSatisfaction" integer NOT NULL,
    "WorkLifeBalance" integer NOT NULL,
    "TotalWorkingYears" integer NOT NULL,
    "YearsAtCompany" integer NOT NULL,
    "YearsInCurrentRole" integer NOT NULL,
    "YearsWithCurrManager" integer NOT NULL,
    "PerformanceScore" double precision NOT NULL,
    "Attrition" character varying(10) NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Employees" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_Employees_Age" CHECK ("Age" > 0),
    CONSTRAINT "FK_Employees_Departments_DepartmentId" FOREIGN KEY ("DepartmentId") REFERENCES "Departments" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Employees_Employees_ManagerId" FOREIGN KEY ("ManagerId") REFERENCES "Employees" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Employees_JobRoles_JobRoleId" FOREIGN KEY ("JobRoleId") REFERENCES "JobRoles" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Users" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "FullName" character varying(150) NOT NULL,
    "Email" character varying(150) NOT NULL,
    "PasswordHash" text NOT NULL,
    "RoleId" integer NOT NULL,
    "EmployeeId" integer,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Users" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Users_Employees_EmployeeId" FOREIGN KEY ("EmployeeId") REFERENCES "Employees" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Users_Roles_RoleId" FOREIGN KEY ("RoleId") REFERENCES "Roles" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Assessments" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeId" integer NOT NULL,
    "CycleId" integer NOT NULL,
    "OverallScore" double precision,
    "Status" character varying(50) NOT NULL,
    "CreatedByUserId" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_Assessments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Assessments_AssessmentCycles_CycleId" FOREIGN KEY ("CycleId") REFERENCES "AssessmentCycles" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Assessments_Employees_EmployeeId" FOREIGN KEY ("EmployeeId") REFERENCES "Employees" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Assessments_Users_CreatedByUserId" FOREIGN KEY ("CreatedByUserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "RefreshTokens" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "TokenHash" text NOT NULL,
    "ExpiresAt" timestamp with time zone NOT NULL,
    "IsRevoked" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "RevokedAt" timestamp with time zone,
    "ReplacedByTokenHash" text,
    CONSTRAINT "PK_RefreshTokens" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_RefreshTokens_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "ActionPlans" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "AssessmentId" integer NOT NULL,
    "EmployeeId" integer NOT NULL,
    "CreatedByUserId" integer NOT NULL,
    "Status" character varying(50) NOT NULL,
    "ApprovedAt" timestamp with time zone,
    "SentAt" timestamp with time zone,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_ActionPlans" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_ActionPlans_Assessments_AssessmentId" FOREIGN KEY ("AssessmentId") REFERENCES "Assessments" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_ActionPlans_Employees_EmployeeId" FOREIGN KEY ("EmployeeId") REFERENCES "Employees" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_ActionPlans_Users_CreatedByUserId" FOREIGN KEY ("CreatedByUserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "AiPredictionRuns" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "AssessmentId" integer NOT NULL,
    "ModelVersionId" integer NOT NULL,
    "RequestedByUserId" integer NOT NULL,
    "Status" character varying(50) NOT NULL,
    "ErrorMessage" text,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_AiPredictionRuns" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_AiPredictionRuns_Assessments_AssessmentId" FOREIGN KEY ("AssessmentId") REFERENCES "Assessments" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_AiPredictionRuns_ModelVersions_ModelVersionId" FOREIGN KEY ("ModelVersionId") REFERENCES "ModelVersions" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_AiPredictionRuns_Users_RequestedByUserId" FOREIGN KEY ("RequestedByUserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "AssessmentScores" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "AssessmentId" integer NOT NULL,
    "CompetencyId" integer NOT NULL,
    "EvaluatorType" character varying(50) NOT NULL,
    "Score" double precision NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_AssessmentScores" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_AssessmentScores_Score" CHECK ("Score" >= 0 AND "Score" <= 5),
    CONSTRAINT "FK_AssessmentScores_Assessments_AssessmentId" FOREIGN KEY ("AssessmentId") REFERENCES "Assessments" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_AssessmentScores_Competencies_CompetencyId" FOREIGN KEY ("CompetencyId") REFERENCES "Competencies" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "FeedbackComments" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "AssessmentId" integer NOT NULL,
    "EvaluatorType" character varying(50) NOT NULL,
    "CommentText" text NOT NULL,
    "SentimentScore" double precision,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_FeedbackComments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_FeedbackComments_Assessments_AssessmentId" FOREIGN KEY ("AssessmentId") REFERENCES "Assessments" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "AiPredictedActions" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PredictionRunId" integer NOT NULL,
    "ActionCode" character varying(50) NOT NULL,
    "Probability" double precision NOT NULL,
    "RankOrder" integer NOT NULL,
    "IsSelected" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_AiPredictedActions" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_AiPredictedActions_Probability" CHECK ("Probability" >= 0 AND "Probability" <= 1),
    CONSTRAINT "FK_AiPredictedActions_AiPredictionRuns_PredictionRunId" FOREIGN KEY ("PredictionRunId") REFERENCES "AiPredictionRuns" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "ActionPlanItems" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "ActionPlanId" integer NOT NULL,
    "ActionCatalogId" character varying(50),
    "AiPredictedActionId" integer,
    "Title" text NOT NULL,
    "Description" text NOT NULL,
    "Resource" text,
    "DeliveryType" character varying(100),
    "Priority" character varying(50) NOT NULL,
    "DueDate" timestamp with time zone,
    "Source" character varying(50) NOT NULL,
    "OrderNo" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_ActionPlanItems" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_ActionPlanItems_ActionCatalogs_ActionCatalogId" FOREIGN KEY ("ActionCatalogId") REFERENCES "ActionCatalogs" ("ActionId") ON DELETE RESTRICT,
    CONSTRAINT "FK_ActionPlanItems_ActionPlans_ActionPlanId" FOREIGN KEY ("ActionPlanId") REFERENCES "ActionPlans" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_ActionPlanItems_AiPredictedActions_AiPredictedActionId" FOREIGN KEY ("AiPredictedActionId") REFERENCES "AiPredictedActions" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "EmployeeTasks" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "ActionPlanItemId" integer NOT NULL,
    "EmployeeId" integer NOT NULL,
    "AssignedByUserId" integer NOT NULL,
    "Status" character varying(50) NOT NULL,
    "AssignedAt" timestamp with time zone NOT NULL,
    "DueDate" timestamp with time zone,
    "CompletedAt" timestamp with time zone,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_EmployeeTasks" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_EmployeeTasks_ActionPlanItems_ActionPlanItemId" FOREIGN KEY ("ActionPlanItemId") REFERENCES "ActionPlanItems" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_EmployeeTasks_Employees_EmployeeId" FOREIGN KEY ("EmployeeId") REFERENCES "Employees" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_EmployeeTasks_Users_AssignedByUserId" FOREIGN KEY ("AssignedByUserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "TaskComments" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TaskId" integer NOT NULL,
    "UserId" integer NOT NULL,
    "CommentText" text NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "IsDeleted" boolean NOT NULL,
    CONSTRAINT "PK_TaskComments" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskComments_EmployeeTasks_TaskId" FOREIGN KEY ("TaskId") REFERENCES "EmployeeTasks" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_TaskComments_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

